@'
import json, os, sys
from collections import Counter, defaultdict
try:
    import openpyxl
except Exception as e:
    print(json.dumps({'openpyxl_import_error': repr(e)}, ensure_ascii=False))
    raise
path = r'D:\Nercar\YongFeng\materials\alloy_cost_calculation\cites\合金基础信息表.xlsx'
wb_formula = openpyxl.load_workbook(path, data_only=False, read_only=False)
wb_values = openpyxl.load_workbook(path, data_only=True, read_only=False)

def cell_value(ws, r, c, values=False):
    v = ws.cell(r, c).value
    if isinstance(v, str):
        return v.replace('\r\n','\n')
    return v

def row_values(ws, r, max_col=None):
    if max_col is None:
        max_col = ws.max_column
    return [cell_value(ws, r, c) for c in range(1, max_col+1)]

def a1(ws, r, c):
    return ws.cell(r, c).coordinate

def compact_row(vals):
    return [v for v in vals]

summary = []
for ws in wb_formula.worksheets:
    wsv = wb_values[ws.title]
    nonempty = []
    formulas = []
    errors = []
    for row in ws.iter_rows():
        for cell in row:
            v = cell.value
            if v is not None:
                nonempty.append(cell.coordinate)
                if isinstance(v, str) and v.startswith('='):
                    formulas.append((cell.coordinate, v))
            vv = wsv[cell.coordinate].value
            if isinstance(vv, str) and vv.startswith('#'):
                errors.append((cell.coordinate, vv, v if isinstance(v, str) and v.startswith('=') else None))
    # identify nonempty columns and first 8 rows exactly
    col_stats = []
    for c in range(1, ws.max_column + 1):
        vals = [ws.cell(r, c).value for r in range(1, ws.max_row + 1)]
        count = sum(v is not None for v in vals)
        samples = []
        for r, v in enumerate(vals, 1):
            if v is not None:
                samples.append((ws.cell(r,c).coordinate, v))
            if len(samples) >= 5:
                break
        if count:
            col_stats.append({'col': openpyxl.utils.get_column_letter(c), 'count': count, 'samples': samples})
    info = {
        'sheet': ws.title,
        'dimensions': ws.calculate_dimension(),
        'max_row': ws.max_row,
        'max_col': ws.max_column,
        'merged_ranges': [str(r) for r in ws.merged_cells.ranges],
        'freeze_panes': ws.freeze_panes,
        'tables': list(ws.tables.keys()),
        'formula_count': len(formulas),
        'formula_samples': formulas[:20],
        'error_count': len(errors),
        'error_samples': errors[:20],
        'first_8_rows': [row_values(ws, r) for r in range(1, min(ws.max_row,8)+1)],
        'col_stats': col_stats,
    }
    summary.append(info)
print(json.dumps(summary, ensure_ascii=False, indent=2, default=str))
